template.css_template:
#{{ID}} .rep-left-panel {
    z-index: 50;
    position: absolute;
    top: 0;
    left: 0;
    width: 150px;
    height: 40px;
    background: {{PRIMARY_BG}};
    color: {{TITLE_COLOR}};
    display: flex;
    flex-direction: column;
    overflow: hidden;
    transform-origin: left center;
    font-family: '{{FONT_FAMILY}}', 'Roboto Condensed', sans-serif;
    box-shadow: {{BOX_SHADOW}};
    opacity: 0;
    transform: {{ANIMATION_IN_TRANSFORM}};
    transition: all {{ANIMATION_DURATION}}s {{ANIMATION_EASE}};
    border-right: 2px solid rgba(255,255,255,0.1);
}
#{{ID}} .rep-clock {
    height: 40px;
    background: {{PRIMARY_BG}};
    display: flex;
    align-items: center;
    justify-content: center;
    font-size: 28px;
    font-weight: 700;
    letter-spacing: 1px;
}

template.js_template:
(() => {
    const root = document.getElementById("{{ID}}");
    const container = root.querySelector(".rep-left-panel");
    const clockEl = root.querySelector(".rep-clock");
    let timer;
    const updateTime = () => {
        const now = new Date();
        const h = String(now.getHours());
        const m = String(now.getMinutes()).padStart(2, "0");
        if(clockEl) clockEl.textContent = h + ":" + m;
    };
    root.__slt_show = () => {
        const tl = GSAPFX.standardIn(container, {{{ANIMATION_IN_JSON}}});
        const textTl = GSAPFX.applyTextEffect(root, {{{TEXT_ANIM_JSON}}});
        if (textTl) {
            if ({{{TEXT_ANIM_SYNC}}}) {
                tl.add(textTl, ">-0.1");
            } else {
                tl.add(textTl, 0);
            }
        }
        updateTime();
        timer = setInterval(updateTime, 1000);
        return tl;
    };
    root.__slt_hide = () => {
        if (typeof timer !== "undefined") clearInterval(timer);
        const textTl = GSAPFX.applyTextOutEffect(root, {{{TEXT_ANIM_OUT_JSON}}});
        const tl = GSAPFX.standardOut(container, {{{ANIMATION_OUT_JSON}}});
        if (textTl) {
            const sync = {{{TEXT_ANIM_OUT_SYNC}}};
            if (sync) {
                const combined = gsap.timeline();
                combined.add(textTl);
                combined.add(tl, ">-0.1");
                return combined;
            } else {
                tl.add(textTl, 0);
            }
        }
        return tl;
    };
})();
